insert into public.training_plans (id, slug, title, description, difficulty, duration_weeks, sessions_per_week, tags, weeks) values
('00000000-0000-4000-a000-000000000001', 'pete-plan', 'Pete Plan', 'The most popular beginner rowing program. Three sessions per week building distance, speed, and endurance over 6 weeks.', 'beginner', 6, 3, '{pete-plan,beginner,popular}', '[{"week_number":1,"title":"Foundation","sessions":[{"day_label":"Day 1","workout_id":"b0000000-0000-0000-0000-000000000001","notes":"5K steady — focus on consistent splits"},{"day_label":"Day 2","workout_id":"b0000000-0000-0000-0000-000000000002","notes":"8x500m — build speed with generous rest"},{"day_label":"Day 3","workout_id":"b0000000-0000-0000-0000-000000000003","notes":"20 min steady — easy effort, technique focus"}]},{"week_number":2,"title":"Building","sessions":[{"day_label":"Day 1","workout_id":"e0000000-0000-0000-0001-000000000001","notes":"5500m steady distance"},{"day_label":"Day 2","workout_id":"e0000000-0000-0000-0002-000000000001","notes":"6x750m intervals"},{"day_label":"Day 3","workout_id":"e0000000-0000-0000-0003-000000000001","notes":"22 min steady state"}]},{"week_number":3,"title":"Progression","sessions":[{"day_label":"Day 1","workout_id":"e0000000-0000-0000-0001-000000000002","notes":"6000m steady distance"},{"day_label":"Day 2","workout_id":"e0000000-0000-0000-0002-000000000002","notes":"4x1000m intervals"},{"day_label":"Day 3","workout_id":"e0000000-0000-0000-0003-000000000002","notes":"24 min steady state"}]},{"week_number":4,"title":"Adaptation","sessions":[{"day_label":"Day 1","workout_id":"e0000000-0000-0000-0001-000000000003","notes":"6500m steady distance"},{"day_label":"Day 2","workout_id":"e0000000-0000-0000-0002-000000000003","notes":"8x500m intervals"},{"day_label":"Day 3","workout_id":"e0000000-0000-0000-0003-000000000003","notes":"20 min steady state"}]},{"week_number":5,"title":"Peak Volume","sessions":[{"day_label":"Day 1","workout_id":"e0000000-0000-0000-0001-000000000004","notes":"7000m steady distance"},{"day_label":"Day 2","workout_id":"e0000000-0000-0000-0002-000000000004","notes":"6x750m intervals"},{"day_label":"Day 3","workout_id":"e0000000-0000-0000-0003-000000000004","notes":"22 min steady state"}]},{"week_number":6,"title":"Consolidation","sessions":[{"day_label":"Day 1","workout_id":"e0000000-0000-0000-0001-000000000005","notes":"7500m steady distance"},{"day_label":"Day 2","workout_id":"e0000000-0000-0000-0002-000000000005","notes":"4x1000m intervals"},{"day_label":"Day 3","workout_id":"e0000000-0000-0000-0003-000000000005","notes":"24 min steady state"}]}]'::jsonb);
