('00000000-0000-4000-a000-000000000002', 'return-to-rowing', 'Return to Rowing', 'Coming back after a break? Four weeks of progressive sessions to rebuild your base safely.', 'beginner', 4, 3, '{return-to-rowing,beginner,comeback}', '[{"week_number":1,"title":"Getting Started","sessions":[{"day_label":"Day 1","workout_id":"f0000000-0000-0000-0001-000000000001"},{"day_label":"Day 2","workout_id":"f0000000-0000-0000-0001-000000000002"},{"day_label":"Day 3","workout_id":"f0000000-0000-0000-0001-000000000003"}]},{"week_number":2,"title":"Building Volume","sessions":[{"day_label":"Day 1","workout_id":"f0000000-0000-0000-0002-000000000001"},{"day_label":"Day 2","workout_id":"f0000000-0000-0000-0002-000000000002"},{"day_label":"Day 3","workout_id":"f0000000-0000-0000-0002-000000000003"}]},{"week_number":3,"title":"Finding Rhythm","sessions":[{"day_label":"Day 1","workout_id":"f0000000-0000-0000-0003-000000000001"},{"day_label":"Day 2","workout_id":"f0000000-0000-0000-0003-000000000002"},{"day_label":"Day 3","workout_id":"f0000000-0000-0000-0003-000000000003"}]},{"week_number":4,"title":"Coming Home","sessions":[{"day_label":"Day 1","workout_id":"f0000000-0000-0000-0004-000000000001"},{"day_label":"Day 2","workout_id":"f0000000-0000-0000-0004-000000000002"},{"day_label":"Day 3","workout_id":"a0000000-0000-0000-0000-000000000003","notes":"30 Min Steady State — you''ve earned it!"}]}]'::jsonb);
insert into public.training_plans (id, slug, title, description, difficulty, duration_weeks, sessions_per_week, tags, weeks) values
