('00000000-0000-4000-a000-000000000004', '2k-race-prep', '2K Race Prep', 'Four weeks of race-specific preparation. Progressive race-pace intervals, threshold work, and a taper into test day.', 'advanced', 4, 3, '{2k-race-prep,advanced,race}', '[{"week_number":1,"title":"Base Building","sessions":[{"day_label":"Day 1","workout_id":"f1000000-0000-0000-0001-000000000001"},{"day_label":"Day 2","workout_id":"f1000000-0000-0000-0001-000000000002"},{"day_label":"Day 3","workout_id":"f1000000-0000-0000-0001-000000000003"}]},{"week_number":2,"title":"Race Pace","sessions":[{"day_label":"Day 1","workout_id":"f1000000-0000-0000-0002-000000000001"},{"day_label":"Day 2","workout_id":"f1000000-0000-0000-0002-000000000002"},{"day_label":"Day 3","workout_id":"f1000000-0000-0000-0002-000000000003"}]},{"week_number":3,"title":"Sharpening","sessions":[{"day_label":"Day 1","workout_id":"f1000000-0000-0000-0003-000000000001"},{"day_label":"Day 2","workout_id":"f1000000-0000-0000-0003-000000000002"},{"day_label":"Day 3","workout_id":"f1000000-0000-0000-0003-000000000003"}]},{"week_number":4,"title":"Race Week","sessions":[{"day_label":"Day 1","workout_id":"f1000000-0000-0000-0004-000000000001","notes":"Easy shakeout"},{"day_label":"Day 2","workout_id":"f1000000-0000-0000-0004-000000000002","notes":"Short openers"},{"day_label":"Day 3","workout_id":"a0000000-0000-0000-0000-000000000001","notes":"2K Test — give it everything!"}]}]'::jsonb);
